      "config": {
        "lr": 3.906e-3,
        "bs": 256
      }
    },
    {
      "id": "h2n3",
      "level": "narrow",
      "claim": "Validation loss improves when increasing batch size from 128 to 256, holding lr fixed at 3.906e-3.",
